const { intent, context } = $json;
const skillRegistry = {
  'write_meta_description': {
    name: 'Meta Description Writer',
    prompt: 'Write a compelling meta description under 160 chars. Include primary keyword near the start. Use active voice and a call-to-action.',
    max_length: 160,
    temperature: 0.3
  },
  'refactor_component': {
    name: 'React Component Refactorer',
    prompt: 'Refactor React components following project patterns: prefer Server Components, extract logic to hooks, use @repo/ui components, keep under 200 lines.',
    conventions: ['use @repo/ui', 'Server Components by default', 'keep under 200 lines']
  },
  'debug_issue': {
    name: 'Systematic Debugger',
    prompt: 'Follow 5-step debug: Reproduce -> Hypothesize -> Investigate -> Root Cause -> Fix. Check git blame for recent changes. Test before and after.',
    steps: ['reproduce', 'hypothesize', 'investigate', 'root_cause', 'fix']
  },
  'write_test': {
    name: 'Test Writer',
    prompt: 'Write Jest unit tests following project patterns. Mock @repo/supabase. Test behavior not implementation. Cover happy path + edge cases.',
    patterns: ['Jest + Testing Library', 'mock @repo/supabase', 'cover edge cases']
  },
  'security_review': {
    name: 'Security Reviewer',
    prompt: 'Review for: RLS policies, auth middleware, SQL injection, XSS, service key usage, department isolation. Check ALL files in the change set.',
    focus: ['RLS', 'auth', 'SQL injection', 'XSS', 'department isolation']
  },
  'optimize_performance': {
    name: 'Performance Optimizer',
    prompt: 'Identify bundle size issues, unnecessary re-renders, missing memoization, large dependencies. Use next/dynamic for heavy components.',
    checks: ['bundle size', 're-renders', 'memoization', 'code splitting']
  }
};
const skill = skillRegistry[intent] || { name: 'Unknown', prompt: 'No specialized skill found for this intent.', fallback: true };
return { skill, matched: !skill.fallback, intent };

const { skill, intent } = $json;
return {
  skill_name: skill.name,
  skill_prompt: skill.prompt,
  metadata: { intent, max_length: skill.max_length, temperature: skill.temperature },
  usage_tip: 'Inject this prompt into your system message for the current task only. Do NOT retain after completion.'
};
